// src/pages/Attendance/AttendanceInboxPage.js
import React, { useState, useEffect, useCallback } from 'react';
import { attendanceAPI, employeeAPI } from '../../api/services';
import { Badge, SkeletonTable, InlineSpinner, Modal } from '../../components/common';
import { Check, X, Plus, Clock } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

// ── Overtime Request Form (for employees) ─────────────────────────────────
function OvertimeRequestModal({ open, onClose, onSubmit, loading }) {
  const [form, setForm] = useState({
    OvertimeDate:   '',
    EstimatedHours: '',
    Reason:         '',
    IsNighttime:    false,
  });
  const [errors, setErrors] = useState({});

  const validate = () => {
    const e = {};
    if (!form.OvertimeDate)                        e.OvertimeDate   = 'Required';
    if (!form.EstimatedHours)                      e.EstimatedHours = 'Required';
    else if (isNaN(form.EstimatedHours) || Number(form.EstimatedHours) <= 0)
                                                   e.EstimatedHours = 'Must be a positive number';
    else if (Number(form.EstimatedHours) > 12)     e.EstimatedHours = 'Cannot exceed 12 hours';
    if (!form.Reason.trim())                       e.Reason         = 'Required';
    return e;
  };

  const handleSubmit = () => {
    const e = validate();
    if (Object.keys(e).length) { setErrors(e); return; }
    onSubmit({ ...form, EstimatedHours: Number(form.EstimatedHours) });
  };

  const set = (k, v) => { setForm(f => ({ ...f, [k]: v })); setErrors(e => ({ ...e, [k]: '' })); };

  return (
    <Modal open={open} onClose={onClose} title="Submit Overtime Request"
      footer={
        <>
          <button className="btn btn-secondary" onClick={onClose} disabled={loading}>Cancel</button>
          <button className="btn btn-primary" onClick={handleSubmit} disabled={loading}>
            {loading ? <InlineSpinner /> : <><Clock size={14} /> Submit Request</>}
          </button>
        </>
      }
    >
      <div style={{ padding: '10px 14px', marginBottom: 16, background: 'var(--blue-dim)', border: '1px solid rgba(59,130,246,0.2)', borderRadius: 'var(--radius-md)', fontSize: '0.82rem', color: 'var(--blue)' }}>
        Submit a request for overtime work. Your manager will review and approve or reject it.
      </div>

      <div className="form-group">
        <label className="form-label required">Overtime Date</label>
        <input className="form-input" type="date" value={form.OvertimeDate}
          min={new Date().toISOString().split('T')[0]}
          onChange={e => set('OvertimeDate', e.target.value)} />
        {errors.OvertimeDate && <div className="form-error">{errors.OvertimeDate}</div>}
      </div>

      <div className="form-group">
        <label className="form-label required">Estimated Hours</label>
        <input className="form-input" type="number" step="0.5" min="0.5" max="12"
          placeholder="e.g. 2.5"
          value={form.EstimatedHours}
          onChange={e => set('EstimatedHours', e.target.value)} />
        {errors.EstimatedHours && <div className="form-error">{errors.EstimatedHours}</div>}
        <div className="form-hint">Maximum 12 hours per request</div>
      </div>

      <div className="form-group">
        <label className="form-label required">Reason</label>
        <textarea className="form-textarea" placeholder="Explain why overtime is needed..."
          value={form.Reason} onChange={e => set('Reason', e.target.value)} />
        {errors.Reason && <div className="form-error">{errors.Reason}</div>}
      </div>

      <div className="form-group">
        <label style={{ display: 'flex', alignItems: 'center', gap: 10, cursor: 'pointer' }}>
          <input type="checkbox" checked={form.IsNighttime}
            onChange={e => set('IsNighttime', e.target.checked)} />
          <span className="form-label" style={{ marginBottom: 0 }}>This is nighttime overtime</span>
        </label>
        <div className="form-hint">Nighttime overtime may attract a higher pay multiplier</div>
      </div>
    </Modal>
  );
}

// ── Main page ──────────────────────────────────────────────────────────────
export default function AttendanceInboxPage() {
  const { user }  = useAuth();
  const isManager = ['Manager','HR','Admin'].includes(user?.role || user?.Role);

  const [tab,         setTab]         = useState(isManager ? 'corrections' : 'overtime');
  const [corrections, setCorrections] = useState([]);
  const [overtime,    setOvertime]    = useState([]);
  const [myRequests,  setMyRequests]  = useState([]);
  const [loading,     setLoading]     = useState(true);
  const [acting,      setActing]      = useState({});
  const [otModal,     setOtModal]     = useState(false);
  const [submitting,  setSubmitting]  = useState(false);

  const toArr = (d, keys) => { if (Array.isArray(d)) return d; for (const k of keys) if (Array.isArray(d?.[k])) return d[k]; return []; };

  const load = useCallback(() => {
    setLoading(true);
    if (isManager) {
      Promise.all([
        attendanceAPI.listCorrections({ status: 'Pending' }),
      ]).then(([c]) => {
        setCorrections(toArr(c.data, ['corrections','data']));
        setLoading(false);
      }).catch(() => setLoading(false));
    } else {
      // Employee: fetch their own overtime requests via the list endpoint
      // The backend returns all records for the authenticated employee
      attendanceAPI.list({ limit: 50 })
        .then(({ data }) => {
          // Extract overtime requests from attendance records
          const records = toArr(data, ['records','attendances','data']);
          // Filter records that have overtime hours or look for a dedicated endpoint
          console.log('📋 MY REQUESTS DATA:', JSON.stringify(data, null, 2).substring(0, 400));
          setMyRequests(records);
          setLoading(false);
        })
        .catch(() => setLoading(false));
    }
  }, [isManager]);

  useEffect(() => { load(); }, [load]);

  // Employee submits overtime request
  const handleSubmitOvertime = async (formData) => {
    setSubmitting(true);
    try {
      const empId = user?.EmployeeID || user?.id || user?.sub;
      await attendanceAPI.submitOvertime({
        EmployeeID:     empId,
        RequestedBy:    empId,
        OvertimeDate:   formData.OvertimeDate,
        EstimatedHours: formData.EstimatedHours,
        Reason:         formData.Reason,
        IsNighttime:    formData.IsNighttime,
      });
      toast.success('Overtime request submitted! Your manager will review it.');
      setOtModal(false);
      load(); // reload to show the new request
    } catch (err) {
      toast.error(err.response?.data?.error?.message || 'Failed to submit request');
    } finally { setSubmitting(false); }
  };

  const actOnCorrection = async (id, action) => {
    setActing(a => ({ ...a, [id]: action }));
    try {
      await attendanceAPI.reviewCorrection(id, { action, reviewNote: '' });
      toast.success(`Correction ${action}d`);
      load();
    } catch (err) {
      toast.error(err.response?.data?.error?.message || 'Action failed');
    } finally { setActing(a => ({ ...a, [id]: null })); }
  };

  const actOnOvertime = async (id, action) => {
    setActing(a => ({ ...a, [`ot_${id}`]: action }));
    try {
      await attendanceAPI.approveOvertime(id, { action });
      toast.success(`Overtime ${action}d`);
      load();
    } catch (err) {
      toast.error(err.response?.data?.error?.message || 'Action failed');
    } finally { setActing(a => ({ ...a, [`ot_${id}`]: null })); }
  };

  const pendingCorr = corrections.filter(c => (c.Status || c.status) === 'Pending').length;

  // ── Employee view ─────────────────────────────────────────────────────────
  if (!isManager) {
    // Filter attendance records that have overtime hours > 0
    const overtimeRecords = myRequests.filter(r =>
      (r.OvertimeHours && Number(r.OvertimeHours) > 0) ||
      (r.overtimeHours && Number(r.overtimeHours) > 0)
    );

    return (
      <>
        <div className="page-header-row">
          <div className="page-header" style={{ marginBottom: 0 }}>
            <h1>My Requests</h1>
            <p>Submit and track your overtime requests</p>
          </div>
          <button className="btn btn-primary" onClick={() => setOtModal(true)}>
            <Plus size={15} /> Request Overtime
          </button>
        </div>

        <div style={{ marginTop: 24 }}>
          {/* Overtime requests table */}
          <div className="card">
            <div className="card-header">
              <div className="card-title">Overtime Requests</div>
              <span className="badge badge-info">{overtimeRecords.length} records</span>
            </div>

            {loading ? (
              <div style={{ display: 'flex', justifyContent: 'center', padding: 40 }}>
                <div className="spinner" />
              </div>
            ) : overtimeRecords.length > 0 ? (
              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      <th>Date</th>
                      <th>Overtime Hours</th>
                      <th>Shift</th>
                      <th>Status</th>
                      <th>Notes</th>
                    </tr>
                  </thead>
                  <tbody>
                    {overtimeRecords.map((r, i) => {
                      const date    = r.AttendanceDate || r.attendanceDate;
                      const otHours = r.OvertimeHours  || r.overtimeHours;
                      const shift   = r.Shift?.ShiftName || '—';
                      const status  = r.Status || r.status || '—';
                      const notes   = r.Notes  || r.notes  || '—';
                      return (
                        <tr key={r.AttendanceID || i}>
                          <td>{date ? new Date(date).toLocaleDateString('en-US',{weekday:'short',month:'short',day:'numeric',year:'numeric'}) : '—'}</td>
                          <td style={{ color: 'var(--gold)', fontWeight: 600 }}>{Number(otHours).toFixed(1)}h</td>
                          <td style={{ color: 'var(--text-secondary)', fontSize: '0.85rem' }}>{shift}</td>
                          <td><Badge status={status}>{status}</Badge></td>
                          <td style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{notes}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            ) : (
              <div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-muted)' }}>
                <Clock size={36} style={{ opacity: 0.4, marginBottom: 12 }} />
                <div style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', marginBottom: 6 }}>
                  No overtime records yet
                </div>
                <div style={{ fontSize: '0.8rem', marginBottom: 16 }}>
                  Submit an overtime request and it will appear here once approved
                </div>
                <button className="btn btn-primary btn-sm" onClick={() => setOtModal(true)}>
                  <Plus size={14} /> Request Overtime
                </button>
              </div>
            )}
          </div>

          {/* How it works */}
          <div className="card" style={{ marginTop: 16 }}>
            <div className="card-header"><div className="card-title">How Overtime Requests Work</div></div>
            {[
              { step: '1', label: 'Submit Request',  desc: 'Fill in the date, estimated hours, and reason for overtime.' },
              { step: '2', label: 'Manager Reviews', desc: 'Your manager receives the request in their inbox and approves or rejects it.' },
              { step: '3', label: 'Notification',    desc: 'You will be notified of the decision via your notifications.' },
              { step: '4', label: 'Payroll Impact',  desc: 'Approved overtime is automatically included in your next payroll calculation.' },
            ].map(({ step, label, desc }) => (
              <div key={step} style={{ display: 'flex', gap: 14, padding: '12px 0', borderBottom: '1px solid var(--border-light)' }}>
                <div style={{
                  width: 28, height: 28, borderRadius: '50%', flexShrink: 0,
                  background: 'var(--gold-glow)', border: '1px solid rgba(240,180,41,0.3)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: '0.75rem', fontWeight: 700, color: 'var(--gold)',
                }}>{step}</div>
                <div>
                  <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>{label}</div>
                  <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginTop: 2 }}>{desc}</div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <OvertimeRequestModal
          open={otModal}
          onClose={() => setOtModal(false)}
          onSubmit={handleSubmitOvertime}
          loading={submitting}
        />
      </>
    );
  }

  // ── Manager view ──────────────────────────────────────────────────────────
  return (
    <>
      <div className="page-header">
        <h1>Manager Inbox</h1>
        <p>Review and action pending attendance requests</p>
      </div>

      <div className="tabs">
        <button className={`tab-btn ${tab === 'corrections' ? 'active' : ''}`} onClick={() => setTab('corrections')}>
          Correction Requests
          {pendingCorr > 0 && <span className="nav-badge" style={{ marginLeft: 6 }}>{pendingCorr}</span>}
        </button>
        <button className={`tab-btn ${tab === 'overtime' ? 'active' : ''}`} onClick={() => setTab('overtime')}>
          Overtime Requests
        </button>
      </div>

      {loading ? <SkeletonTable rows={5} /> : tab === 'corrections' ? (
        corrections.length === 0 ? (
          <div className="card">
            <div style={{ textAlign: 'center', padding: 50, color: 'var(--text-muted)' }}>
              <div style={{ fontSize: '2rem', marginBottom: 8 }}>✅</div>
              No pending correction requests
            </div>
          </div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Employee</th><th>Date</th><th>Req. Check-In</th><th>Req. Check-Out</th><th>Reason</th><th>Status</th><th>Action</th></tr>
              </thead>
              <tbody>
                {corrections.map((c, i) => {
                  const id     = c.CorrectionID || c.correctionID || c.id;
                  const status = c.Status || c.status || 'Pending';
                  const fmtT   = (v) => { if (!v) return '—'; try { const d = new Date(v); return isNaN(d) ? v : d.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'}); } catch { return v; } };
                  return (
                    <tr key={id || i}>
                      <td style={{ fontWeight: 500 }}>
                        {c.Employee?.FullName || c.EmployeeName || c.employeeName || '—'}
                        {c.Employee?.EmployeeCode && <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>{c.Employee.EmployeeCode}</div>}
                      </td>
                      <td>{(c.Attendance?.AttendanceDate || c.AttendanceDate || c.attendanceDate) ? new Date(c.Attendance?.AttendanceDate || c.AttendanceDate || c.attendanceDate).toLocaleDateString() : '—'}</td>
                      <td style={{ color: 'var(--green)', fontWeight: 500 }}>{fmtT(c.CorrectedCheckIn  || c.correctedCheckIn)}</td>
                      <td style={{ color: 'var(--red)',   fontWeight: 500 }}>{fmtT(c.CorrectedCheckOut || c.correctedCheckOut)}</td>
                      <td style={{ maxWidth: 200 }}><span className="truncate" style={{ display: 'block', fontSize: '0.82rem' }}>{c.Reason || c.reason || '—'}</span></td>
                      <td><Badge status={status}>{status}</Badge></td>
                      <td>
                        {status === 'Pending' && (
                          <div style={{ display: 'flex', gap: 6 }}>
                            <button className="btn btn-success btn-sm" onClick={() => actOnCorrection(id,'approve')} disabled={!!acting[id]}>
                              {acting[id] === 'approve' ? <InlineSpinner /> : <><Check size={13}/> Approve</>}
                            </button>
                            <button className="btn btn-danger btn-sm" onClick={() => actOnCorrection(id,'reject')} disabled={!!acting[id]}>
                              {acting[id] === 'reject' ? <InlineSpinner /> : <><X size={13}/> Reject</>}
                            </button>
                          </div>
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )
      ) : (
        // Overtime tab — manager view
        overtime.length === 0 ? (
          <div className="card">
            <div style={{ textAlign: 'center', padding: 50, color: 'var(--text-muted)' }}>
              <div style={{ fontSize: '2rem', marginBottom: 8 }}>✅</div>
              No pending overtime requests
            </div>
          </div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Employee</th><th>Date</th><th>Est. Hours</th><th>Reason</th><th>Nighttime</th><th>Status</th><th>Action</th></tr>
              </thead>
              <tbody>
                {overtime.map((ot, i) => {
                  const id     = ot.OvertimeRequestID || ot.overtimeRequestID || ot.id;
                  const status = ot.Status || ot.status || 'Pending';
                  return (
                    <tr key={id || i}>
                      <td style={{ fontWeight: 500 }}>
                        {ot.Employee?.FullName || ot.employeeName || '—'}
                        {ot.Employee?.EmployeeCode && <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>{ot.Employee.EmployeeCode}</div>}
                      </td>
                      <td>{ot.OvertimeDate ? new Date(ot.OvertimeDate).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'}) : '—'}</td>
                      <td style={{ color: 'var(--gold)', fontWeight: 600 }}>{ot.EstimatedHours ? `${ot.EstimatedHours}h` : '—'}</td>
                      <td style={{ maxWidth: 200 }}><span className="truncate" style={{ display: 'block', fontSize: '0.82rem' }}>{ot.Reason || ot.reason || '—'}</span></td>
                      <td><Badge status={ot.IsNighttime ? 'Active' : 'Inactive'}>{ot.IsNighttime ? 'Yes' : 'No'}</Badge></td>
                      <td><Badge status={status}>{status}</Badge></td>
                      <td>
                        {status === 'Pending' && (
                          <div style={{ display: 'flex', gap: 6 }}>
                            <button className="btn btn-success btn-sm" onClick={() => actOnOvertime(id,'approve')} disabled={!!acting[`ot_${id}`]}>
                              {acting[`ot_${id}`] === 'approve' ? <InlineSpinner /> : <><Check size={13}/> Approve</>}
                            </button>
                            <button className="btn btn-danger btn-sm" onClick={() => actOnOvertime(id,'reject')} disabled={!!acting[`ot_${id}`]}>
                              {acting[`ot_${id}`] === 'reject' ? <InlineSpinner /> : <><X size={13}/> Reject</>}
                            </button>
                          </div>
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )
      )}
    </>
  );
}
